-- Module 6 — GNSS/Geodesy
('fb02c000-0000-0000-0000-000000000001','Lambert Conformal Conic','A conic projection used for State Plane zones that are wider east–west. Meridians converge to a central point; parallels are concentric circular arcs.','Conic; E–W zones.',NULL,NULL,NULL,ARRAY['lambert','projection','spcs']::text[],ARRAY['fs-flashcards','fs-thin-topics','fs-m6']::text[],'fs:f5000006-0000-0000-0000-000000000006','intermediate',true,'approved'),
('fb02c000-0000-0000-0000-000000000002','Transverse Mercator','A cylindrical projection used for State Plane zones that are longer north–south (and for UTM). Minimizes distortion along a central meridian.','Cylindrical; N–S zones; UTM.',NULL,NULL,NULL,ARRAY['transverse mercator','projection','utm','spcs']::text[],ARRAY['fs-flashcards','fs-thin-topics','fs-m6']::text[],'fs:f5000006-0000-0000-0000-000000000006','intermediate',true,'approved'),
('fb02c000-0000-0000-0000-000000000003','Spherical Law of Cosines (sides)','For a spherical triangle: cos c = cos a cos b + sin a sin b cos C. Solves the third side from two sides and the included angle.','cos c = cos a cos b + sin a sin b cos C.',NULL,NULL,NULL,ARRAY['spherical trigonometry','law of cosines','geodesy']::text[],ARRAY['fs-flashcards','fs-thin-topics','fs-m6']::text[],'fs:f5000006-0000-0000-0000-000000000006','advanced',true,'approved'),
('fb02c000-0000-0000-0000-000000000004','Geoid Height (N)','The separation between the ellipsoid and the geoid at a point. Relates the height systems: h = H + N (ellipsoidal = orthometric + geoid height).','h = H + N.',NULL,NULL,NULL,ARRAY['geoid height','undulation','h=H+N']::text[],ARRAY['fs-flashcards','fs-thin-topics','fs-m6']::text[],'fs:f5000006-0000-0000-0000-000000000006','intermediate',true,'approved'),
