('fb02c000-0000-0000-0000-000000000005','Obliterated Corner','A PLSS corner with no remaining monument traces, but whose position is recoverable from reliable testimony and acceptable evidence.','Recoverable by testimony/evidence.',NULL,NULL,NULL,ARRAY['obliterated corner','plss','testimony']::text[],ARRAY['fs-flashcards','fs-thin-topics','fs-m7']::text[],'fs:f5000007-0000-0000-0000-000000000007','intermediate',true,'approved'),
('fb02c000-0000-0000-0000-000000000006','Lost Corner','A PLSS corner whose position cannot be recovered from evidence or testimony; it must be re-established by proportionate measurement (single/double proportion).','Re-set by proportioning.',NULL,NULL,NULL,ARRAY['lost corner','proportion','plss']::text[],ARRAY['fs-flashcards','fs-thin-topics','fs-m7']::text[],'fs:f5000007-0000-0000-0000-000000000007','intermediate',true,'approved'),
